// Parse GA4 response and calculate performance
const gaResponse = $input.first().json;
const rows = gaResponse.rows || [];
const threshold = 1.5; // 1.5% conversion rate minimum
const minSessions = 200; // Minimum traffic before evaluation

const results = [];

for (const row of rows) {
  const variantId = row.dimensionValues[0]?.value || 'unknown';
  const pagePath = row.dimensionValues[1]?.value || '/';
  const sessions = parseInt(row.metricValues[0]?.value) || 0;
  const conversions = parseInt(row.metricValues[1]?.value) || 0;
  const engagementRate = parseFloat(row.metricValues[2]?.value) || 0;

  const conversionRate = sessions > 0 ? (conversions / sessions) * 100 : 0;

  // Only evaluate variants with enough traffic
  if (sessions >= minSessions) {
    results.push({
      variantId,
      pagePath,
      sessions,
      conversions,
      conversionRate: conversionRate.toFixed(2),
      engagementRate: (engagementRate * 100).toFixed(2),
      underperforms: conversionRate < threshold,
      action: conversionRate < threshold ? 'KILL' : 'KEEP',
      timestamp: new Date().toISOString()
    });
  } else {
    // Not enough data yet
    results.push({
      variantId,
      pagePath,
      sessions,
      conversions,
      conversionRate: conversionRate.toFixed(2),
      action: 'WAIT',
      reason: `Only ${sessions}/${minSessions} sessions`,
      timestamp: new Date().toISOString()
    });
  }
}

// Sort by conversion rate descending
results.sort((a, b) => parseFloat(b.conversionRate) - parseFloat(a.conversionRate));

return results.map(r => ({ json: r }));

// Remove killed variant from active rotation
const variant = $input.first().json;

// Store killed variants (would connect to your variant DB)
const killedVariant = {
  variantId: variant.variantId,
  killedAt: new Date().toISOString(),
  finalConversionRate: variant.conversionRate,
  totalSessions: variant.sessions,
  reason: 'Below 1.5% conversion threshold'
};

return [{ json: killedVariant }];

